// Convierte cada dosis vencida en un payload de Telegram con botones ✅/❌
const body = $input.first().json;
const due = (body && body.due) || [];
const chatId = $env.NEXUS_TELEGRAM_CHAT_ID;
const out = [];
for (const d of due) {
  const t = d.time || '';
  const kindEmoji = d.kind === 'vitamina' ? '🟡' : d.kind === 'suplemento' ? '🥤' : '💊';
  const lines = [
    `${kindEmoji} *Hora de tu ${d.kind || 'medicamento'}*`,
    ``,
    `*${d.name}*${d.dose ? ' · ' + d.dose : ''}`,
    d.purpose ? `_Para: ${d.purpose}_` : '',
    t ? `🕐 ${t}` : '',
  ].filter(Boolean).join('\n');
  out.push({ json: {
    chat_id: chatId,
    text: lines,
    parse_mode: 'Markdown',
    reply_markup: {
      inline_keyboard: [[
        { text: '✅ Lo tomé', callback_data: `med:${d.medication_id}:${t}:t` },
        { text: '❌ No lo tomé', callback_data: `med:${d.medication_id}:${t}:n` }
      ]]
    }
  }});
}
return out;
